import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classic() {
        // [0,30] overlaps both [5,10] and [15,20] — needs 2 rooms
        assertEquals(2, new Solution().minRooms(new int[][]{{0,30},{5,10},{15,20}}));
    }

    @Test
    void noOverlap() {
        // [7,10] and [2,4] are disjoint — 1 room suffices
        assertEquals(1, new Solution().minRooms(new int[][]{{7,10},{2,4}}));
    }

    @Test
    void endpointTouchSharesRoom() {
        // [1,5] ends at 5 and [5,10] starts at 5 — same room reused
        assertEquals(1, new Solution().minRooms(new int[][]{{1,5},{5,10}}));
    }

    @Test
    void allConcurrent() {
        // All start at 1, end at 10 — need 4 rooms
        assertEquals(4, new Solution().minRooms(new int[][]{{1,10},{1,10},{1,10},{1,10}}));
    }

    @Test
    void cascadingChain() {
        // Each meeting starts before the previous ends — peak is 3
        assertEquals(3, new Solution().minRooms(new int[][]{{1,10},{2,9},{3,8},{11,12}}));
    }

    @Test
    void singleMeeting() {
        assertEquals(1, new Solution().minRooms(new int[][]{{0,5}}));
    }

    @Test
    void emptyInput() {
        assertEquals(0, new Solution().minRooms(new int[][]{}));
    }
}
